import { Routes, Route, Navigate } from "react-router-dom";

import Login from "./pages/Login";
import HackerDashboard from "./pages/HackerDashboard";
import CompanyDashboard from "./pages/CompanyDashboard";
import CompanyPendingBugs from "./pages/CompanyPendingBugs";
import CompanyBugHistory from "./pages/CompanyBugHistory";
import SubmitBug from "./pages/SubmitBug";
import MyBugs from "./pages/MyBugs";
import Wallet from "./pages/Wallet";
import Register from "./pages/Register";
import CompanyAnalytics from "./pages/CompanyAnalytics";
import CompanyWallet from "./pages/CompanyWallet";

export default function App() {
  const token = localStorage.getItem("token");
  const role = localStorage.getItem("role");

  return (
    <Routes>
      {/* FORCE LOGIN FIRST */}
      <Route path="/" element={<Navigate to="/login" replace />} />
      <Route path="/login" element={<Login />} />

      {/* Hacker */}
      <Route
        path="/hacker"
        element={token && role === "hacker" ? <HackerDashboard /> : <Navigate to="/login" replace />}
      />
      <Route
        path="/submit-bug"
        element={token && role === "hacker" ? <SubmitBug /> : <Navigate to="/login" replace />}
      />
      <Route
        path="/my-bugs"
        element={token && role === "hacker" ? <MyBugs /> : <Navigate to="/login" replace />}
      />
      <Route
        path="/wallet"
        element={token && role === "hacker" ? <Wallet /> : <Navigate to="/login" replace />}
      />

      {/* Company */}
      <Route
        path="/company"
        element={token && role === "company" ? <CompanyDashboard /> : <Navigate to="/login" replace />}
      />
      <Route
        path="/company/pending"
        element={token && role === "company" ? <CompanyPendingBugs /> : <Navigate to="/login" replace />}
      />
      <Route
        path="/company/history"
        element={token && role === "company" ? <CompanyBugHistory /> : <Navigate to="/login" replace />}
      />
      <Route
        path="/company/analytics"
        element={token && role === "company" ? <CompanyAnalytics /> : <Navigate to="/login" replace />}
      />
      <Route
        path="/company/wallet"
        element={token && role === "company" ? <CompanyWallet /> : <Navigate to="/login" replace />}
      />

      <Route path="/register" element={<Register />} />

      {/* Any unknown route */}
      <Route path="*" element={<Navigate to="/login" replace />} />
    </Routes>
  );
}
